sql:
SELECT rt, response 
FROM responses 
ORDER BY rt DESC;

SELECT DISTINCT UPPER(principal_investigator) AS principal_investigator, status
FROM experiments
WHERE status = 'ongoing';

SELECT subjects.subject_name, subjects.consent_form
FROM subjects
INNER JOIN responses ON subjects.subject_id = responses.subject_id;

SELECT *
FROM user_accounts
WHERE EXISTS (SELECT 1 FROM access_logs WHERE access_logs.user_id = user_accounts.user_id);
